import SwiftUIstruct AuthView: View {    @EnvironmentObject var authVM: AuthViewModel    @State private var email = ""    @State private var password = ""    @State private var isSignUp = false    var body: some View {        ZStack {            Color.black.ignoresSafeArea()            VStack(spacing: 28) {                // Header                VStack(spacing: 8) {                    Image(systemName: "globe.americas.fill")                        .font(.system(size: 60))                        .foregroundStyle(                            LinearGradient(colors: [.orange, .red],                                           startPoint: .topLeading,                                           endPoint: .bottomTrailing)                        )                    Text("NEO Tracker")                        .font(.largeTitle.bold())                        .foregroundColor(.white)                    Text(isSignUp ? "Create your account" : "Sign in to continue")                        .font(.subheadline)                        .foregroundColor(.gray)                }                .padding(.top, 60)                // Fields                VStack(spacing: 14) {                    TextField("Email", text: $email)                        .keyboardType(.emailAddress)                        .autocapitalization(.none)                        .padding()                        .background(Color.white.opacity(0.07))                        .cornerRadius(12)                        .foregroundColor(.white)                        .overlay(RoundedRectangle(cornerRadius: 12)                            .stroke(Color.white.opacity(0.1), lineWidth: 1))                    SecureField("Password", text: $password)                        .padding()                        .background(Color.white.opacity(0.07))                        .cornerRadius(12)                        .foregroundColor(.white)                        .overlay(RoundedRectangle(cornerRadius: 12)                            .stroke(Color.white.opacity(0.1), lineWidth: 1))                }                .padding(.horizontal)                // Error                if let error = authVM.errorMessage {                    Text(error)                        .font(.caption)                        .foregroundColor(.red)                        .multilineTextAlignment(.center)                        .padding(.horizontal)                }                // Primary Button                Button {                    Task {                        if isSignUp {                            await authVM.signUp(email: email, password: password)                        } else {                            await authVM.signIn(email: email, password: password)                        }                    }                } label: {                    Group {                        if authVM.isLoading {                            ProgressView().tint(.white)                        } else {                            Text(isSignUp ? "Create Account" : "Sign In")                                .font(.headline)                        }                    }                    .frame(maxWidth: .infinity)                    .padding()                    .background(Color.orange)                    .foregroundColor(.white)                    .cornerRadius(14)                }                .padding(.horizontal)                .disabled(authVM.isLoading || email.isEmpty || password.isEmpty)                // Toggle                Button {                    isSignUp.toggle()                    authVM.errorMessage = nil                } label: {                    Text(isSignUp                         ? "Already have an account? Sign In"                         : "Don't have an account? Sign Up")                        .font(.subheadline)                        .foregroundColor(.orange)                }                Spacer()            }        }    }}